code = """import json, pandas as pd

cases = pd.DataFrame(var_call_TkefwhI2suAuEQVHmwp5G6S7)
accts = pd.DataFrame(var_call_2N10map50g58QgmKdQWaaBCM)

# clean account ids (strip leading #) and states
accts['account_id_clean'] = accts['account_id_raw'].astype(str).str.strip().str.lstrip('#')
accts['shipping_state'] = accts['shipping_state'].astype(str).str.strip()

cases['account_id_clean'] = cases['account_id_clean'].astype(str).str.strip().str.lstrip('#')
cases['closure_days'] = pd.to_numeric(cases['closure_days'], errors='coerce')

m = cases.merge(accts[['account_id_clean','shipping_state']], on='account_id_clean', how='left')

# keep only valid 2-letter state codes
m = m[m['shipping_state'].str.fullmatch(r'[A-Z]{2}', na=False) & m['closure_days'].notna()]

g = m.groupby('shipping_state', as_index=False)['closure_days'].mean()
# quickest = smallest mean closure
best = g.sort_values(['closure_days','shipping_state']).head(1)
ans = best.iloc[0]['shipping_state'] if len(best) else None

print('__RESULT__:')
print(json.dumps(ans))"""

